<template>
  <view class="recharge-list">
    <view class="recharge-item" :class="{on:currIndex == index}" v-for="item,index in rechargeList" :key="index" @click="handelClick(item,index)">
      <view class="money">
        <text>{{item.money}} </text> {{ ' ' }} 元
      </view>
      <view class="give">
        赠送：<text>{{item.give_money}}</text> 元
      </view>
    </view>
  </view>
</template>

<script>
export default {
  props: {
    rechargeList:{
      type:Array,
      default:() =>[]
    }
  },
  components: {

  },
  data() {
    return {
      currIndex:-1,
    };
  },
  computed: {

  },
  watch: {

  },
  created() {

  },
  mounted() {

  },
  methods: {
    handelClick(item,index){
      this.currIndex = index
      this.$emit('item-click',item)
    }
  },
};
</script>

<style scoped lang="scss" scoped>
.recharge-list{
  display: flex;
  flex-wrap: wrap;
  gap: 24rpx;
  line-height: initial;
  .recharge-item{
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background-color:#F4F4F4;
    border-radius: 16rpx;
    color: #656565;
	width: 212rpx;
    padding: 20rpx 16rpx;
	font-size: 24rpx;
    cursor: pointer;
    user-select: none;
    .money{
      & >text{
        font-size: 32rpx;
      }
    }
    .give{
      margin-top: 20rpx;
    }
  }
  .on{
       color: #ffffff;
       background: linear-gradient(90deg, #ff8c00b3 0%, #ff8c00 100%);
  }
}
</style>
