<template>
	<u-popup v-model="popupShow" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
		:border-radius="20" width="600rpx" :closeable="true" :z-index="100" @close="close" @open="open">
		<view class="popup-content">
			<view style="width: 500rpx;">
				<u-parse :html="renderData.tip" v-if="renderData.tip" :selectable="true"
					:show-with-animation="true"></u-parse>

				<u-form :labelWidth="140" ref="form" :model="formData">
					<u-form-item label="选择银行">
						<view @click="showBank=true"><text class="mr-10">{{selectBankTitle}}</text><u-icon
								name="edit-pen" color="#999"></u-icon></view>
						<u-select v-model="showBank" :default-value="[selectBankIndex]" :list="bankList"
							@confirm="onBankChange"></u-select>
					</u-form-item>
					<u-form-item label="收款方" v-if="renderData.true_name">
						<view style="line-height: 34rpx;word-break:break-all"
							@click="handelCopyText(renderData.true_name)">
							{{renderData.true_name}}<u-icon style="margin-left: 4px;" name="zhuanfa" :size="30"
								color="rgb(94,94,94)"></u-icon>
						</view>
					</u-form-item>
					<u-form-item label="对公账号" v-if="renderData.account">
						<view style="line-height: 34rpx;word-break:break-all"
							@click="handelCopyText(renderData.account)">
							{{renderData.account}}
							<u-icon style="margin-left: 4px;" name="zhuanfa" :size="30" color="rgb(94,94,94)"></u-icon>
						</view>
					</u-form-item>

					<u-form-item label="支行名称" v-if="renderData.bank_branch">
						<view style="line-height: 34rpx;word-break:break-all"
							@click="handelCopyText(renderData.bank_branch)">
							{{renderData.bank_branch}}<u-icon style="margin-left: 4px;" name="zhuanfa" :size="30"
								color="rgb(94,94,94)"></u-icon>
						</view>
					</u-form-item>
					<u-form-item label="付款金额">
						<text style="color: red"> {{ renderData.total_price }}</text> 元
					</u-form-item>
					<u-form-item label="订单号" prop="trade_sn"><u-input v-model="formData.trade_sn" /></u-form-item>
					<u-form-item label="转账凭证" prop="image">
						<Upload v-model="formData.image" :customBtn="true" :addBtnIconSize="40" addBtnColor="#BCBDC2"
							uploadText="添加图片" :showProgress="true" />
					</u-form-item>
					<u-form-item label="备注" prop="user_mark">
						<u-input v-model="formData.user_mark" type="textarea" />
					</u-form-item>
					<u-form-item :border-bottom="false">
						<view class="btn bg-blue" style="width: 100%;" @click="$u.throttle(ok, 1000)">确认支付</view>
					</u-form-item>
				</u-form>
			</view>
		</view>
	</u-popup>

</template>

<script>
	import Upload from '@/components/upload/kuyu'
	import _ from 'lodash'

	export default {
		components: {
			Upload,
		},
		props: {
			show: {
				type: Boolean,
				default: false,
			},
			source: {
				type: Object,
				default: () => {}
			},
		},
		data() {
			return {
				popupShow: false,

				formData: {
					trade_sn: '',
					image: '',
					pay_id: '',
					money: '',
					user_mark: ''
				},
				rules: {
					trade_sn: [{
						required: true,
						trigger: ['change', 'blur'],
						message: '请填写转账单号'
					}],
					image: [{
						required: true,
						trigger: ['change', 'blur'],
						message: '请上传转账凭证'
					}]
				},
				bankPayList: [], // 银行列表
				selectBankId: 0,
				payItem: null, // 当前支付方式

				showBank: false,
			}
		},
		computed: {
			// 银行列表
			bankList() {
				return this.bankPayList.map((item) => {
					return {
						value: item.id,
						label: item.title,
					}
				})
			},
			selectBankTitle() {
				const find = this.bankList.find((item) => item.value === this.selectBankId)
				return find ? find.label : ''
			},
			selectBankIndex() {
				return this.bankList.findIndex((item) => item.value === this.selectBankId)
			},
			// 选择的银行
			selectedBank() {
				return this.bankPayList.find((item) => item.id === this.selectBankId)
			},
			renderData() {
				if (this.selectBankId) {
					return this.selectedBank.pay_data
				} else {
					return {}
				}
			},
			title() {
				if (this.selectedBank) {
					return this.selectedBank.title
				} else {
					return '银行卡-转账加款'
				}
			}
		},
		watch: {
			show(nv) {
				this.popupShow = nv
			},
			source: {
				handler(nv) {
					if (!_.isEmpty(nv)) {
						const {
							payItem,
							bankPayList
						} = nv
						this.bankPayList = bankPayList || []
						if (bankPayList.length) {
							this.selectBankId = bankPayList[0].id
						}
						this.payItem = payItem || {}
					}
				},
				deep: true,
			},
			selectBankId(nv) {
				if (nv) {
					this.formData.pay_id = this.selectedBank.id
					this.formData.money = this.renderData.total_price
				}
			}
		},
		methods: {
			open() {
				this.$refs.form.setRules(this.rules)
			},
			close() {
				this.formData = this.$options.data().formData
				this.selectBankId = 0
				this.$emit('update:show', false)
			},
			// 转账加款-确认支付
			async ok() {
				this.$refs.form.validate(async (valid) => {
					if (valid) {
						await this.$u.api.bankData(this.formData)
						this.popupShow = false
						this.$util.msg('提交成功请等待审核')
					} else {
						console.log('验证失败')
					}
				})
			},
			// 复制文本
			handelCopyText(txt) {
				uni.setClipboardData({
					data: txt,
					success() {
						uni.showToast({
							title: '复制成功',
							icon: 'success'
						});
					},
					fail() {
						uni.showToast({
							title: '复制失败',
							icon: 'none'
						});
					}
				});
			},
			onBankChange(e) {
				this.selectBankId = e[0].value
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		display: flex;
		align-items: center;
		padding: 40rpx;
		flex-direction: column;
		gap: 20rpx;

		&>.title {
			font-weight: bolder;
			font-size: 30rpx;
		}
	}

	.bank-list {
		display: flex;
		flex-wrap: wrap;
		align-items: center;
		gap: 20px;

		.bank-item {
			display: flex;
			flex-wrap: nowrap;
			align-items: center;
			justify-content: center;
			padding: 8px 6px;
			border: 1px solid #e5e5e5;
			border-radius: 10px;
			gap: 5px;
			cursor: pointer;
			user-select: none;
			max-width: 120px;

			.bank-item-title {
				flex: 1;
				overflow: hidden;
			}
		}

		.active {
			border: 1px solid #409eff;
		}
	}
</style>