<template>
	<view class="body">
		<u-navbar :z-index="980" :is-back="true" :custom-back="pageBack" title="充值余额"></u-navbar>
		<view class="box" v-show="showForm">
			<view class="box-child">
				<view class="recharge-box" v-if="type == 1 &&  defaultpay.name !='code'">
					<view class="title">
						<view class="left">
							在线充值
						</view>
					</view>
					<view class="form-item">
						<text class="label">
							￥
						</text>
						<u-input :custom-style="{
							color: '#1e2331',
							fontWeight: 600,
							fontSize: '64rpx',
						}" v-model="money" placeholder="请输入充值金额" type="digit"
							placeholder-style="color:#d8d8d8;font-size:30rpx;font-wight:400;" @input="moneyInput"
							@blur='onBlur' />
					</view>

					<text class="tips">
						{{placeholder}}
					</text>
				</view>
				<view class="recharge-box" v-if="type == 2 || defaultpay.name=='code'">
					<view class="title">
						<view class="left">
							加款卡充值
						</view>
					</view>

					<view class="form-item">

						<u-input :custom-style="{
							color: '#1e2331',
						
							fontSize: '32rpx',
						}" v-model="recharge_code" placeholder="请在此黏贴加款卡密码"
							placeholder-style="color:#d8d8d8;font-size:30rpx;font-wight:400;" />
					</view>
					<text class="tips">
						请确保加款卡密码填写正确
					</text>
				</view>
			</view>
			<view class="box-child" v-if="rechargeList.length &&  defaultpay.name!='code'">
				<QuickRechargeList :recharge-list="rechargeList" @item-click="handelRechargeItemClick" />
			</view>
		</view>
		<view class="box" v-if="type ==1">
			<view class="box-child">
				<view class='pay-list'>
					<view class="item" v-for="(item,index) in payList" :key="index" @click="choosepay(index)">
						<view class="title-box">
							<image class="img" :src="$util.img(item.img)" mode="aspectFit"></image>
							<view class="title">
								{{item.title}}
								<text class="pay-tips" v-if="item.tips">{{item.tips}}</text>
							</view>
							<view class="fee" v-if="item.fee>0">
								（手续费{{item.fee}}元)
							</view>
							<view class="rate" v-if="item.rate > 0">(充值费率{{Number(item.rate)}}%)</view>
						</view>

						<view class="checked">
							<text style="color: red;" class="iconfont"
								:class="{'icon-danxuanxuanzhong':index ==defaultpayindex,'icon-danxuan':index !=defaultpayindex}"></text>
						</view>
					</view>
				</view>

			</view>
		</view>
		<view class="btn-box">
			<view class="buy-button" @click="goodsBuy">
				立即充值
			</view>
			<view class="buy-button" style="margin-top: 10px;background-image: linear-gradient(135deg,#2867f0,#467bef);"
				@click="$util.on(currPay.recharge_url)" v-if="currPay.name=='code' && currPay.recharge_url">
				购买地址
			</view>
		</view>
		<u-popup v-model="qrcodeshow" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
			:border-radius="20" width="500rpx" :closeable="true" @close="stopPayStatus">
			<view class="popup-content">
				<view class="title">
					{{qrcode_title}}
				</view>
				<view class="qrcode">
					<uqrcode :hide="!qrcode_image_show" :loading="true" v-if="!qrcode_image_show"
						@complete="uqrcodeComplete" ref="uqrcode" @longpress="saveqrcode" canvas-id="qrcode"
						sizeUnit="rpx" size="400" :value="qrcode_url"></uqrcode>

					<image style="width: 100%;height: 100%;" v-if="qrcode_image_show" :src="qrcode_image"
						mode="aspectFit"></image>
				</view>
				<view @click="copyLink">
					<view v-if="copyMark">收款人姓名： <text style="color:red">{{copyMark}}</text></view>
					<view v-else>点击复制链接或截图扫码</view>
				</view>
			</view>
		</u-popup>
		<OpenWind :show-type="2" ref='open_wind' :title="currPay.title+'提示'" />
		<alipayuser-popup :show.sync="alipayuserPopupShow" :source="alipayuserPopupData" @pay-ok="handelAlipayUserOk" />
		<bank-popup :show.sync="bankPopupShow" :source="bankPopupData" :scene="1" />
		<payjun-popup :show.sync="payjunPopupShow" :source="alipayuserPopupData" @pay-ok="handelAlipayUserOk" />
	</view>
</template>

<script>
	import QuickRechargeList from './components/QuickRechargeList'
	import OpenWind from '@/components/OpenWind'
	import AlipayUserPopup from '@/components/alipayuser-popup'
	import BankPopup from '@/components/bank-popup'
	import _ from 'lodash'
	import PayjunPopup from '@/components/payjun-popup'
	export default {
		components: {
			QuickRechargeList,
			OpenWind,
			'alipayuser-popup': AlipayUserPopup,
			'bank-popup': BankPopup,
				'payjun-popup': PayjunPopup,
		},
		data() {
			return {

				loading: false,
				scrollTop: 0,

				sys: this.$util.sys(),

				nav_opacity: 0,
				header_opacity: 1,

				tpl: {
					accountname: ''
				},
				userMobile: '',
				goods: { //当前选中商品
					id: 0,
					goods_name: '', //商品名称
					goods_img: '', //商品图片
					goods_info: '', //商品详情
					cate_name: '', //分类
					tpl: [], //模板
					goods_price: 0,
					face_value: 0,
				},
				//当前商品
				params: {


				},
				payConfig: {

				},

				defaultpay: {}, //选中的支付方式
				payList: [

				],

				//当前支付订单号

				ordersn: '',
				order_id: '',
				total_price: 0,

				qrcode_title: '',
				qrcode_url: '1',
				qrcodeshow: false,
				copyMark: '',

				trade_password: '', //交易密码
				paystatusTimer: null,
				noneed_userinput_pass: false, //不需要输入交易密码
				input_pwd: false,
				input_finish: false, //交易密码是否输入完整

				qrcode_image_show: false,
				qrcode_image: '',

				qiehuan_img: '',
				money: '',
				type: 1,
				recharge_code: '',
				fee: '0.00', //手续费
				rate: 0,
				rate_min: '0.00',
				user_fee: 0,
				wxpaycode: '',

				rechargeList: [], //快捷充值列表

				alipayuserPopupShow: false, //显示转账加款弹框
				payjunPopupShow: false, //显示骏卡支付弹框
				alipayuserPopupData: {}, //弹框渲染的内容

				bankPopupShow: false,
				bankPopupData: {},

				defaultpayindex: 0,

			}
		},
		computed: {
			currPay() {
				return this.defaultpay || {}
			},
			placeholder() {
				this.moneyInput();
				return `手续费 ${this.fee} 元`;
			},
			showForm() {
				if (this.currPay.name == 'alipayuser' && this.currPay.change_type == 3) {
					return false
				} else {
					return true
				}
			}
		},
		onLoad(e) {
			this.loadData()


			// if(e.ordersn){
			// 	this.ordersn = e.ordersn
			// }
			// console.log(e);

			//支付回调
			if (e.ordersn && e.code) {
				this.ordersn = e.ordersn
				this.defaultpay = {
					name: e.pay_type,
					id: e.pay_id
				}
				this.wxpaycode = e.code
				this.pay()
			} else {
				if (e.ordersn && e.pay_type) {

					this.paystatusTimer = setInterval(() => {
						this.ordersn = e.ordersn
						this.paystatus()
					}, 1000)
				}
			}
		},
		onUnload() {
			this.stopPayStatus()
		},
		methods: {

			//二维码生成成功
			uqrcodeComplete(e) {
				this.$refs.uqrcode.toTempFilePath({
					success: res => {
						this.qrcode_image = res.tempFilePath
						this.qrcode_image_show = true
					}
				});
			},
			copyLink() {
				uni.setClipboardData({
					data: this.qrcode_url,
					success() {
						uni.showToast({
							title: '复制成功',
							icon: 'success'
						});
					},
					fail() {
						uni.showToast({
							title: '复制失败',
							icon: 'none'
						});
					}
				});
			},
			async loadData() {

				// this.loading = true;
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})

				await this.$u.api.rechargeConfig(this.params)
					.then(res => {

						//处理数据

						this.payList = res.payList
						this.user_fee = res.user_fee
						this.qiehuan_img = res.qiehuan_img

						if (this.payList.length > 0) {
							this.choosepay(0)
						}

						this.rechargeList = res.recharge_list
					}).catch(res => {
						console.log(res);
					})

				uni.hideLoading()
				// this.loading = false;
			},
			//选择支付方式
			choosepay(index) {
				this.defaultpayindex = index
				let item = this.payList[index]
				this.defaultpay = item
				this.rate = item.rate
				this.rate_min = item.rate_min

				this.getFee()

				if (item.recharge_tip) {
					this.$refs['open_wind'].show(item.recharge_tip)
				}

			},
			//获取
			getFee() {
				if (this.money > 0) {

					let fee = this.$util.bcmul(this.money, this.$util.bcdiv(this.rate, 100));
					fee = fee + this.$util.bcmul(this.money, this.$util.bcdiv(this.user_fee, 100));


					if (Number(Number(fee).toFixed(3)) > Number(Number(fee).toFixed(2))) {
						fee = this.$util.bcadd(0.01, Number(fee).toFixed(2));
					} else {
						fee = Number(fee).toFixed(2);
					}
					if (fee < this.rate_min) {
						this.fee = this.rate_min
					} else {
						this.fee = fee
					}

				} else {
					this.fee = '0.00'
				}
			},

			moneyInput(value) {
				this.getFee()
				//从缓存中获取
				uni.getStorage({
					key: 'recharge_data',
					success: (res) => {
						let data = JSON.parse(res.data)
						if (data.money != this.money && this.ordersn) {
							this.ordersn = ''
						}
					},
					fail: (e) => {

					}
				});
				uni.setStorage({
					key: 'recharge_data',
					data: JSON.stringify({
						money: this.money,
					})
				});
			},

			saveqrcode(e) {
				console.log(e);
			},
			//支付
			goodsBuy: _.throttle(function() {
				if (this.money) {
					if (this.defaultpay.name != 'code') {
						this.pay()
					} else {
						this.codeRecharge()
					}
				} else {
					if (this.defaultpay.name != 'code') {
						if(!this.showForm){
							this.pay()
						}else{
							this.$util.msg('请输入充值金额')
						}
					} else {
						this.codeRecharge()
					}
				}
			}, 1000),
			//加款卡充值
			codeRecharge() {

				this.$u.api.pay({
					code: this.recharge_code,
					pay_type: 'code',
				}).then((res) => {
					this.$util.msg('本次充值' + res.recharge_price + '元');

					this.$u.vuex('userinfo.balance', res.balance);
					setTimeout(() => {
						this.$util.redirect('/pages/ucenter_sub/moneylist');
					}, 1000)
				})
			},
			//发起支付
			pay() {

				this.qrcode_image_show = false

				var that = this
				switch (this.defaultpay.name) {
					case 'alipay': //支付宝支付
						this.qrcode_title = '支付宝支付'
						break;
					case 'alipayuser': //转账加款
						this.qrcode_title = '转账加款'
						break
					case 'wxpay': //微信支付
					case 'wechat': //微信支付
						this.qrcode_title = '微信支付'
						break;
					case 'qqpay': //QQ支付
						this.qrcode_title = 'QQ支付'
						break;
				}


				let wxpaycode = this.wxpaycode
				this.wxpaycode = ''

				this.$u.api.pay({
					ordersn: this.ordersn,
					pay_type: this.defaultpay.name,
					pay_id: this.defaultpay.id,
					trade_password: this.trade_password,
					money: this.money,
					wxpaycode: wxpaycode,
				}).then(async (res) => {
					if (this.paystatusTimer) {
						clearInterval(this.paystatusTimer)
					}

					if (this.defaultpay.name === 'bank') {
						const bankPayList = res.pay_list[0].bank_pay_list
						this.bankPopupData = {
							payItem: this.defaultpay,
							bankPayList
						}
						this.bankPopupShow = true
					} else {
						if (this.defaultpay.name != 'defaultpay') {
							this.ordersn = res.order_sn
							this.paystatusTimer = setInterval(() => {
								this.paystatus()
							}, 2000)
						}
						//1 二维码支付 2 跳转网址 3 打开应用 4 微信公众号支付 5 微信小程序支付 6 微信app支付 7 支付宝app支付
						switch (res.url_type) {
							case 1:
								this.qrcode_url = res.url
								//生成二维码
								//#ifdef H5

								//收款人身份
								if (this.defaultpay.name == 'alipayuser' && res.pay_data && res.pay_data
									.true_name) {
									this.copyMark = res.pay_data.true_name;
								} else {
									this.copyMark = '';
								}

								if (this.defaultpay.name == 'alipay' || this.defaultpay.name == 'alipayuser') {
									this.$util.openAppUrl(this.qrcode_url)
								}
								//#endif
								this.qrcodeshow = true
								break;
							case 2:

								//#ifdef MP-WEIXIN

								if (this.defaultpay.name == 'alipay') {
									this.qrcode_url = res.url
									// window.location.href = res.url
									this.qrcodeshow = true



								}

								//#endif

								//#ifdef H5

								//微信浏览器

								// if (this.$util.browserType('weixin')) {
								// uni.setStorage({
								// 	key: 'topay_link',
								// 	data: JSON.stringify({
								// 		link:  encodeURIComponent(res.url),
								// 	})
								// });

								// 	this.$util.on('/pages/common/topay?id=' + this.order_id + '&link=' +
								// 		encodeURIComponent(res.url) + '&from=' + this.defaultpay)
								// } else {
								window.location.href = res.url
								// }


								//#endif
								//#ifdef APP
								this.$util.on(res.url);

								//#endif

								break;
							case 3:


								//#ifdef H5
								window.location.href = res.url
								//#endif

								break;

							case 4: //微信公众号支付
								//#ifdef H5
								jWeixin.config({
									debug: false, // 开启调试模式,调用的所有api的返回值会在客户端alert出来，若要查看传入的参数，可以在pc端打开，参数信息会通过log打出，仅在pc端时才会打印。
									appId: res.pay_data.appId, // 必填，公众号的唯一标识
									timestamp: res.pay_data.timeStamp, // 必填，生成签名的时间戳
									nonceStr: res.pay_data.nonceStr, // 必填，生成签名的随机串
									signature: res.pay_data.paySign, // 必填，签名
									jsApiList: [ //这里是需要用到的接口名称  
										'checkJsApi', //判断当前客户端版本是否支持指定JS接口  
										'onMenuShareAppMessage', //分享接口  
										'getLocation', //获取位置  
										'openLocation', //打开位置  
										'scanQRCode', //扫一扫接口  
										'chooseWXPay', //微信支付  
										'chooseImage', //拍照或从手机相册中选图接口  
										'previewImage', //预览图片接口  
										'uploadImage' //上传图片  
									], // 必填，需要使用的JS接口列表
									openId: this.userinfo.wxgzh_openid
								});
								//付款
								jWeixin.chooseWXPay({
									appId: res.pay_data.appId,
									timestamp: res.pay_data
										.timeStamp, // 支付签名时间戳，注意微信jssdk中的所有使用timestamp字段均为小写。但最新版的支付后台生成签名使用的timeStamp字段名需大写其中的S字符
									nonceStr: res.pay_data.nonceStr, // 支付签名随机串，不长于 32
									package: res.pay_data
										.package, // 统一支付接口返回的prepay_id参数值，提交格式如：prepay_id=\*\*\*）
									signType: res.pay_data.signType, // 签名方式，默认为'SHA1'，使用新版支付需传入'MD5'
									paySign: res.pay_data.paySign, // 支付签名
									success: function(res) {


										// 余额支付直接跳到订单详情
										that.ordersn = ''
										that.order_id = ''
										if (that.paystatusTimer) {
											clearInterval(that.paystatusTimer)
										}
										that.$util.msg('支付成功');
										// setTimeout(() => {
										// 	that.$util.on('/pages/order/info?id=' + that.order_id);
										// }, 1000)
										setTimeout(() => {
											that.$util.redirect(
												'/pages/ucenter_sub/moneylist');
										}, 1000)

									},
									cancel: function(res) {
										that.$util.msg('取消支付');
										if (that.paystatusTimer) {
											clearInterval(that.paystatusTimer)
										}
									},
									fail: function(res) {
										that.$util.msg('付款失败');
										if (that.paystatusTimer) {
											clearInterval(that.paystatusTimer)
										}

									}
								});

								//#endif
								break;
							case 5: //微信小程序支付

								// #ifdef MP
								let pay_data = res.pay_data
								let mp_pay_name = ''
								if (uni.requestOrderPayment) {
									mp_pay_name = 'requestOrderPayment'
								} else {
									mp_pay_name = 'requestPayment'
								}

								uni.showLoading({
									title: `支付中`
								});

								uni[mp_pay_name]({
									timeStamp: pay_data.timeStamp,
									nonceStr: pay_data.nonceStr,
									package: pay_data.package,
									signType: pay_data.signType,
									paySign: pay_data.paySign,
									success: function(res) {
										uni.hideLoading();

										that.$util.msg(res.msg);

									},
									fail: function(e) {
										uni.hideLoading();
										that.$util.msg('取消支付')
									},
									complete: function(e) {
										uni.hideLoading();
										if (e.errMsg == 'requestPayment:cancel' || e.errMsg ==
											'requestOrderPayment:cancel') return
										that.$util.msg('取消支付');
									},
								});
								// #endif




								break;
							case 6: //微信app支付


								// #ifdef APP-PLUS
								console.log(res)
								uni.showLoading({
									mask: true,
									title: '支付中...'
								});
								uni.requestPayment({
									provider: 'wxpay',
									orderInfo: res.pay_data,
									success: (e) => {
										that.$util.msg(`支付成功`)


									},
									fail: (e) => {
										that.$util.msg(`支付失败`)

									},
									complete: () => {
										// 余额支付直接跳到订单详情
										that.ordersn = ''
										that.order_id = ''
										if (that.paystatusTimer) {
											clearInterval(that.paystatusTimer)
										}

										uni.hideLoading()
									},
								});
								// #endif

								break;
							case 7: //支付宝app支付
								// #ifdef APP-PLUS

								uni.showLoading({
									mask: true,
									title: '支付中...'
								});
								uni.requestPayment({
									provider: 'alipay',
									orderInfo: res.pay_data,
									success: (e) => {
										that.$util.msg(`支付成功`)


									},
									fail: (e) => {
										console.log(e)
										that.$util.msg(`支付失败`)

									},
									complete: (e) => {
										console.log(e)
										// 余额支付直接跳到订单详情
										that.ordersn = ''
										that.order_id = ''
										if (that.paystatusTimer) {
											clearInterval(that.paystatusTimer)
										}

										uni.hideLoading()
									},
								});
								// #endif

								break;
							case 8: //转账加款							
								this.alipayuserPopupData = {
									trade_sn: '',
									order_sn: this.ordersn,
									pay_id: this.defaultpay.id,
									...res.pay_data
								}
								if (this.alipayuserPopupData.is_trade_sn) {
									if (that.paystatusTimer) {
										clearInterval(that.paystatusTimer)
									}
								}
								if (this.alipayuserPopupData.is_need_account) {
									{
										this.$util.msg('请使用支付宝提现账号付款')
										setTimeout(() => {
											this.$util.on('/pages/ucenter_sub/draw')
										}, 2000)
									}
								} else
									this.alipayuserPopupShow = true
								break;
								case 9: //骏卡支付
									this.alipayuserPopupData = {
										trade_sn: '',
										order_sn: this.ordersn,
										pay_id: this.defaultpay.id,
										...res.pay_data
									}
								
									this.payjunPopupShow = true
									break;
						}
					}
				})
			},

			paystatus() {

				this.$u.api.payStatus({
					ordersn: this.ordersn,
					ordertype: 2,
					trade_sn: this.alipayuserPopupData.trade_sn
				}).then((res) => {
				
					if (res.status == 1) {
						let order_id = this.order_id
						this.ordersn = ''
						this.order_id = ''

						this.$util.msg('充值成功');

						clearInterval(this.paystatusTimer)

						this.$u.vuex('userinfo.balance', this.$util.bcadd(this.userinfo.balance, this.money));
						setTimeout(() => {
							this.$util.redirect('/pages/ucenter_sub/moneylist');
						}, 1000)

					}
				}).catch((e) => {
					clearInterval(this.paystatusTimer)
				})
			},
			toPay() {
				//交易密码输入完成

				if (this.input_finish) {
					this.goodsBuy()
				} else {
					this.$util.msg('请输入完整交易密码');

				}
				this.$refs.trade_password_box.clearLoading()
			},
			inputPwdChange(value) {
				this.input_finish = false;
			},
			inputPwdFinish(value) {
				this.trade_password = value
				this.input_finish = true;
			},
			async createOrder() {

				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				let createData = {
					create_type: 2,
					money: this.money,
				};


				for (let key in this.params) {
					createData[key] = this.params[key]
				}
				for (let key in this.tpl) {
					createData[key] = this.tpl[key]
				}


				await this.$u.api.createOrder(createData)
					.then(res => {
						//处理数据
						this.ordersn = res.ordersn
						this.order_id = res.order_id
						this.pay()

					}).catch(res => {
						console.log(res);
					})

				uni.hideLoading()
			},

			//分享
			share() {

			},
			// 快捷选项点击
			handelRechargeItemClick(e) {
				this.money = e.money.replace(/^\D*(\d*(?:\.\d{0,2})?).*$/g, '$1')
			},
			// 图片预览
			handelGoodsImgClick(url) {
				uni.previewImage({
					urls: [url],
					current: 0
				})
			},
			// 复制文本
			handelCopyText(txt) {
				uni.setClipboardData({
					data: txt,
					success() {
						uni.showToast({
							title: '复制成功',
							icon: 'success'
						});
					},
					fail() {
						uni.showToast({
							title: '复制失败',
							icon: 'none'
						});
					}
				});
			},
			// 转账加款-确认支付
			handelAlipayuserConfirm() {
				if (!this.alipayuserPopupData.trade_sn) {
					this.$util.msg('请输入订单号');
					return
				}
				this.$u.api.payStatus({
					ordersn: this.ordersn,
					ordertype: 2,
					trade_sn: this.alipayuserPopupData.trade_sn
				}).then((res) => {

					if (res.status == 1) {
						let order_id = this.order_id
						this.ordersn = ''
						this.order_id = ''

						this.$util.msg('充值成功');

						clearInterval(this.paystatusTimer)

						this.$u.vuex('userinfo.balance', this.$util.bcadd(this.userinfo.balance, this.money));
						setTimeout(() => {
							this.$util.redirect('/pages/ucenter_sub/moneylist');
						}, 1000)

					} else {
						this.$util.msg('订单未支付')
					}
				})
			},
			pageBack() {
				const pages = getCurrentPages()
				if (pages[pages.length - 2] && pages[pages.length - 2].route == 'pages/common/topay') {
					this.$util.redirect('pages/ucenter/index')
				} else {
					this.$util.back()
				}
			},
			onBlur() {
				this.money = this.money.replace(/^\D*(\d*(?:\.\d{0,2})?).*$/g, '$1');
				if (this.money != '') {
					this.money = parseFloat(this.money).toFixed(2);
				} else {
					this.money = parseFloat(0).toFixed(2);
				}
			},
			stopPayStatus() {
				if (this.paystatusTimer) {
					clearInterval(this.paystatusTimer)
					this.paystatusTimer = null
				}
			},
			handelAlipayUserOk({
				url
			}) {
				this.stopPayStatus()
this.payjunPopupShow = false
				this.ordersn = ''
				this.order_id = ''
				setTimeout(() => {
					this.$util.on(url)
				}, 1000)
			},
		}
	}
</script>


